      "mainEntity": [
        {
          "@type": "Question",
          "name": "How is a foreign currency receivable restated at the year end?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "A foreign currency receivable is restated at the closing exchange rate on 31 March, with the difference taken to the statement of profit and loss under AS 11 or Ind AS 21. An invoice of USD 10,000 booked at Rs 83 and closing at Rs 86 gives an unrealised gain of Rs 30,000 recognised in that year."
          }
        },
        {
          "@type": "Question",
          "name": "What is the difference between a realised and an unrealised exchange gain on receivables?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "A realised exchange gain arises when the customer actually pays and the rupees received differ from the amount booked, while an unrealised gain arises only from restating an open invoice at the balance sheet date. Both go to the profit and loss account, but only the realised part has cash behind it, which matters when computing advance tax."
          }
        },
        {
          "@type": "Question",
          "name": "How long can export receivables stay outstanding under RBI rules?",
          "acceptedAnswer": {
            "@type": "Answer",
            "text": "Export proceeds must be realised and repatriated within nine months from the date of export under FEMA regulations administered by RBI. Overdue invoices show in the EDPMS system and the bank asks for an extension or a write off approval. Unrealised export bills beyond the limit can block future shipping bill clearance, so the receivables ledger should be reconciled to EDPMS monthly."
          }
        }
      ]
